scripts.env:inject:
node -e "try{require('fs').readFileSync('.env','utf8').split('
').forEach(l=>{const[k,...v]=l.split('=');if(k&&v.length)process.env[k.trim()]=v.join('=').trim()})}catch(e){}require('fs').writeFileSync('src/environments/environment.ts','export const environment = {
  mapboxToken: ''+(process.env.MAPBOX_TOKEN||'')+'',
  vapidPublicKey: ''+(process.env.VAPID_PUBLIC_KEY||'')+'',
};
');console.log('Wrote environment.ts')"

scripts.env:restore:
node -e "const f='src/environments/environment.ts';const c='export const environment = {
  mapboxToken: 'MAPBOX_TOKEN_PLACEHOLDER',
  vapidPublicKey: 'VAPID_PUBLIC_KEY_PLACEHOLDER',
};
';require('fs').writeFileSync(f,c);console.log('Restored placeholders')"
